@ARTICLE{10.1016/j.ecoenv.2022.114351,
	author = {Guo, P. and Lei, M. and Hu, S. and Xu, Z. and Zhou, Y. and Zhou, P. and Huang, R.},
	title = {Long-term LDR exposure may induce cognitive impairments: A possible association through targeting gut microbiota-gut-brain axis},
	journal = {Ecotoxicology and Environmental Safety},
	year = {2023},
	abstract = {Environmental and occupational low-dose radiation (LDR) exposure may be harmful for health but the previous reports regarding effect of LDR on cognition are contradictory. Here we investigated the effect of long-term LDR exposure on cognition. In this study, male Balb/c mice’ cognitive functions were tested at 15 weeks after being exposed to 0.5 Gy LDR in 10 fractions at each dose of 0.05 Gy. The results demonstrated that long-term LDR exposure increases escape latency and the time spent in finding exits in mice compared with non LDR exposure. Meanwhile, the inflammation-related proteins including NFκB and p38 also increased. Lipopolysaccharide (LPS) increased and short-chain fatty acid (SCFA) levels decreased following long term LDR exposure. Treatment with microbiota-derived LPS and SCFAs reversed these effects in mice. Furthermore, the gut barrier integrity was damaged in a time-dependent manner with the decreased expression of intestinal epithelial-related biomarkers such as ZO-1 and occludin. Mechanistically, long after exposure to LDR, increased LPS levels may cause cognitive impairment through the regulation of Akt/mTOR signaling in the mouse hippocampus. These findings provide new insight into the clinical applications of LDR and suggest that the gut microbiota–plasma LPS and SCFAs–brain axis may underlie long-term LDR-induced cognition effects. © 2022 The Authors ER - ER - ER -},
	doi = {10.1016/j.ecoenv.2022.114351},
	type = {JOUR}
}

@ARTICLE{10.1136/oemed-2025-110223,
	author = {Mai, J.Z. and Velazquez-Kronen, R. and Linet, M.S. and Freudenheim, J.L. and Wactawski-Wende, J. and Kwon, T. and Lee, C. and Preston, D.L. and Alexander, B.H. and Cahoon, E.K. and Kitahara, C.M.},
	title = {Low-dose occupational ionising radiation exposure and gastrointestinal cancer mortality among US radiologic technologists, 1983-2021},
	journal = {Occupational and Environmental Medicine},
	year = {2025},
	abstract = {Objectives We evaluated the relationship between cumulative occupational ionising radiation exposure and gastrointestinal cancer mortality in a cohort of US radiologic technologists (USRT). Methods Among 106 072 USRT cohort participants who were cancer-free at completion of the baseline questionnaire (1983-1998, representing completion of the first (1983-1989) or second questionnaire (1994-1998) as baseline), protracted low- to moderate-dose occupational ionising radiation exposure was evaluated in relation to gastrointestinal cancer mortality over the follow-up period (through 2021). Poisson regression was used to calculate linear excess relative rates (ERR) of gastrointestinal cancer mortality per 100 mGy colon-absorbed dose (mean=15 mGy; range 0-754 mGy), lagged 10 years, adjusting the baseline mortality rate for attained age, sex, birth cohort, race and other potential confounders (alcohol consumption, smoking, body mass index, non-steroidal anti-inflammatory drug (NSAID) use). Results Over follow-up (mean=31.4 years), 570 pancreatic, 504 colon, 171 liver, 131 oesophageal, 106 stomach and 73 rectal cancer deaths were identified. In the full cohort, no significant dose-response relationships were observed for pancreatic, colon, liver, oesophageal or rectal cancer mortality. A non-significant positive association for stomach cancer mortality was observed in a model minimally adjusted for attained age, sex and birth cohort; however, this association was attenuated after additionally adjusting for race and NSAID use (ERR/100mGy=1.56; 95% CI <0 to 159). Evidence for effect modification for stomach cancer mortality was observed by birth year (P-interaction=0.002) and year first worked (0.004), although based on small number of deaths, most positive associations within categories were not statistically significant. Conclusions In this nationwide cohort of radiologic technologists, cumulative occupational ionising radiation exposure was not clearly associated with mortality from specific gastrointestinal cancers. Studies with cancer incidence follow-up and pooled analyses of ionising radiation-exposed populations may provide more comprehensive and robust dose-response estimates for specific gastrointestinal cancers. © Author(s) (or their employer(s)) 2025. No commercial re-use. See rights and permissions. Published by BMJ Group. ER - ER - ER -},
	doi = {10.1136/oemed-2025-110223},
	type = {JOUR}
}

@ARTICLE{10.1371/journal.pone.0303356,
	author = {Staffurth, J.N. and Sivell, S. and Baddeley, E. and Ahmedzai, S. and Andreyev, H.J. and Campbell, S. and Farnell, D.J.J. and Ferguson, C. and Green, J. and Muls, A. and O’Shea, R. and Pickett, S. and Smith, L. and Taylor, S. and Nelson, A.},
	title = {The impact of specialised gastroenterology services for pelvic radiation disease (PRD): Results from the prospective multi-centre EAGLE study},
	journal = {PLoS ONE},
	year = {2025},
	abstract = {To undertake a mixed-methodology implementation study to improve the well-being of men with gastrointestinal late effects following radical radiotherapy for prostate cancer. All men completed a validated screening tool for late bowel effects (ALERT-B) and the Gastrointestinal Symptom Rating Score (GSRS); men with a positive score on ALERT-B were offered management following a peer reviewed algorithm for pelvic radiation disease (PRD). Health-related quality of life (HRQoL) at baseline, 6 and 12 months; and healthcare resource usage (HRU) and patient, support-giver, staff experience and acceptability of staff training (qualitative analysis) were assessed. Two nurse- and one doctor-led gastroenterology services were set up in three UK cancer centres. Men (n = 339) who had had radical radiotherapy for prostate cancer at least 6 months previously, were recruited; of which 91/339 were eligible to participate; 58/91 men (63.7%) accepted the referral. Diagnoses included: radiation proctopathy (n = 18); bile acid malabsorption (n = 15); fructose or lactose intolerance and/or small intestinal bacterial overgrowth (n = 20); vitamin B12/D deficiency (n = 20). Increases in quality of life, sexual activity and/or sexual function, and decrease in specific symptoms (e.g. bowel-related or urinary) between 6 and 12 months were observed. Limited HRU modelling suggested staff costs were £117-£185, depending on the service model; total costs averaged £2,243 per patient. Both staff and patients welcomed the new service although there was concern about long-term funding and sustainability beyond the timeframe of the study (qualitative). PRD is increasingly recognised worldwide as an ongoing consequence of curative pelvic radiotherapy, despite widespread implementation of advanced radiotherapy techniques. Specialised services following national guidelines are required. © 2025 Staffurth et al. This is an open access article distributed under the terms of the Creative Commons Attribution License, which permits unrestricted use, distribution, and reproduction in any medium, provided the original author and source are credited. ER - ER - ER -},
	doi = {10.1371/journal.pone.0303356},
	type = {JOUR}
}

@ARTICLE{10.18502/jehsd.v9i1.15118,
	author = {Mortazavi, M. and Ahmadinejad, P. and Arjmand, S. and Derakhshanjazari, M.},
	title = {Health Effects Associated with Occupational Exposure to Gamma Radiation in Aircrew: A Case Study on Mehrabad Airport in 2021},
	journal = {Journal of Environmental Health and Sustainable Development},
	year = {2024},
	abstract = {Introduction: Aircrew is exposed to harmful levels of gamma radiation with unknown effects. This study aims to investigate occupational exposure to cosmic gamma radiation and its associated health effects among the aircrew members of Iran Airlines. Methods: This analytical cross-sectional study was carried out on the crew from four internal flights departing from Mehrabad Airport in 2021. The participants were divided into two groups of 100 aircrew members flying on low-altitude and high-altitude routes, and the history of their illnesses in the past thres years was extracted from medical records. The average annual effective dose (ED) of gamma radiation for the aircrew was measured by dosimeter (CEM DT-9501), and data analysis was done using SPSS16 software. Results: This study found that the average annual ED of gamma rays was approximately 1.5 millisieverts higher in flight crews on high-altitude flights compared to the low-altitude ones. Moreover, a significant relationship was observed between exposure to gamma and occupational disease in the studied subjects (P < 0.05). Therefore, the risk of gastrointestinal, skin, and cardiovascular diseases was 3.55, 3.63, and 12.4 times higher for the crew on high-altitude flights compared with those on low-altitude flights. Conclusion: High-altitude flights are associated with increased exposure to gamma radiation, leading to a threefold higher risk of occupational diseases such as gastrointestinal, skin, and cardiovascular conditions among aircrew members. These findings highlight the importance of reducing health risks of exposure to gamma rays in aviation industry and emphasize the need for preventive measures to protect the well-being of aircrew personnel. © (2024), (Shahid Sadoughi University of Medical Sciences). All Rights Reserved. ER - ER - ER -},
	doi = {10.18502/jehsd.v9i1.15118},
	type = {JOUR}
}

@ARTICLE{10.1038/s42003-022-03929-1,
	author = {Ju, Z. and Guo, P. and Xiang, J. and Lei, R. and Ren, G. and Zhou, M. and Yang, X. and Zhou, P. and Huang, R.},
	title = {Low-dose radiation exaggerates HFD-induced metabolic dysfunction by gut microbiota through PA-PYCR1 axis},
	journal = {Communications Biology},
	year = {2022},
	abstract = {Co-exposure of High-fat-diet (HFD) behavior and environmental low-dose radiation (LDR) is common among majority occupational workers, but the synergism of this co-exposure in metabolic health is poorly understood. This study aimed to investigate the impact of gut microbiota and its metabolites on the regulation of HFD accompanied by LDR-associated with metabolic dysfunction and insulin resistance. Here, we reported that Parasutterella was markedly elevated in the gut microbiota of mice in co-exposure of HFD and LDR, accompanied by increased pyrrolidinecarboxylic acid (PA) level in both intestine and plasma. Transplantation of fecal microbiota from mice with co-exposure HFD and LDR with metabolic dysfunction resulted in increased disruption of metabolic dysfunction, insulin resistance and increased PYCR1 (Pyrroline-5-carboxylate reductase 1) expression. Mechanistically, intestinal barrier was damaged more serious in mice with co-exposure of HFD and LDR, leading high PA level in plasma, activating PYCR1 expression to inhibit insulin Akt/mTOR (AKT kinase-transforming protein/Serine threonine-protein kinase) signaling pathway to aggravate HFD-induced metabolic impairments. This study suggests a new avenue for interventions against western diet companied with low dose radiation exposure-driven metabolic impairments. © 2022, The Author(s). ER - ER - ER -},
	doi = {10.1038/s42003-022-03929-1},
	type = {JOUR}
}

@ARTICLE{10.21668/health.risk/2024.1.09.eng,
	author = {Zhuntova, G.V. and Bannikova, M.V. and Azizova, T.V.},
	title = {THE RISK OF COLORECTAL CANCER INCIDENCE IN A COHORT OF INDIVIDUALS OCCUPATIONALLY EXPOSED TO IONIZING RADIATION},
	journal = {Health Risk Analysis},
	year = {2024},
	abstract = {The increased risk of colorectal cancer following ionizing radiation exposure was demonstrated in a number of epidemiological studies. Earlier, no impact of occupational radiation exposure on colorectal cancer incidence or mortality was observed in a cohort of workers of the nuclear industrial facility, Mayak Production Association (PA). Extension of the follow-up of the cohort and improvement of dose estimates for personnel made it possible to update the earlier findings. The study objective is to assess the risk of colorectal cancer incidence associated with chronic occupational radiation exposure taking into account non-radiation factor effects. The study cohort included 22,377 workers employed at the reactor, plutonium-producing and radiochemical plants of Mayak PA (hiring period 1948–1982; follow-up period ended on December 31, 2018). Using the Poisson regression (EPICURE software), the relative risks (RRs with 95 % confidence intervals, (95 % CI)) of colorectal cancer incidence were estimated depending on the most significant non-radiation factors (sex, age, smoking, alcohol consumption, excessive body mass and obesity, intestinal polyps, chronic colitis). These values were also calculated for certain ranges of occupational exposure doses relying on data provided by ‘The Mayak Worker Dosimetry System – 2013’. The linear model was used to analyze the dose-response relationship. In the study cohort, the RR of colorectal cancer incidence was lower in females than in males: 0.72 (95 % CI: 0.55; 0.96) for colon and 0.48 (95 % CI: 0.34; 0.67) for rectum. The increased RR of the rectum cancer incidence was observed for cases with intestinal polyps: 3.42 (95 % CI: 1.68; 6.19). The colon cancer incidence risk increased with increasing age of workers, but other non-radiation factors were not shown to affect the results. This study supported the earlier results: no association was observed between the risk of colorectal cancer incidence and doses of occupational external gamma-ray or internal alpha-particle exposures. © Zhuntova G.V., Bannikova M.V., Azizova T.V., 2024 ER - ER - ER -},
	doi = {10.21668/health.risk/2024.1.09.eng},
	type = {JOUR}
}

@ARTICLE{10.1039/d2em00209d,
	author = {Hettiarachchi, E. and Das, M. and Cadol, D. and Frey, B.A. and Rubasinghege, G.},
	title = {The fate of inhaled uranium-containing particles upon clearance to gastrointestinal tract},
	journal = {Environmental Science: Processes and Impacts},
	year = {2022},
	abstract = {Uranium-bearing respirable dust can cause various health problems, such as cardiovascular and neurological disorders, cancers, immunosuppression, and autoimmunity. Exposure to elevated levels of uranium is linked to many such health conditions in Navajo Nation residents in northwestern New Mexico. Most studies have focused on the fate of inhaled dust particles (<4 μm) in the lungs. However, larger-sized inhaled particles (10-20 μm) can be cleared to the human gastrointestinal tract (GIT), thereby enabling them to interact with stomach and intestinal fluids. Despite the vital importance of understanding the fate of uranium-bearing solids entering the human GIT and their impact on body tissues, cells, and gut microbiota, our understanding remains limited. This study investigated uranium solubility from dust and sediment samples collected near two uranium mines in the Grants Mining District in New Mexico in two simulated gastrointestinal fluids representing fasting conditions in the GIT: Simulated Gastric Fluid (SGF) and Simulated Intestinal Fluid (SIF). The dissolution of uranium from dust depends on its mineralogy, fluid pH, and composition. The dust samples from the Jackpile mine favored higher solubility in the SIF solution, whereas the sediment samples from the St. Anthony Mine favored higher solubility in the SGF solution. Further, geochemical calculations performed with the PHREEQC modeling program suggested that samples rich in the minerals andersonite, tyuyamunite, and/or autunite have higher uranium dissolution in the SIF solution than in the SGF solution. We also tested the effect of added kaolinite and microcline, which are both present in some samples. The ratio of dissolved uranium in SGF relative to SIF decreases with the addition of kaolinite for all mineral phases but andersonite. With the addition of microcline, the ratio of dissolved uranium in SGF relative to SIF decreases for all the tested uranium minerals. The most prevalent oxidation state of dissolved uranium was computationally determined as +6, U(vi). The geochemical calculations made with PHREEQC agree with the experimentally observed results. Therefore, this study gives insight into the mineralogy-controlled toxicological assessment of uranium-containing inhaled dust cleared to the gastrointestinal tract. © 2022 The Royal Society of Chemistry. ER - ER - ER -},
	doi = {10.1039/d2em00209d},
	type = {JOUR}
}

@ARTICLE{10.3748/wjg.v28.i38.5557,
	author = {Jun-Yu, T. and Wen, J. and Xia-Qing, Y. and Ru, W. and Gang-Hua, L. and Ding-Wei, G. and Zhong-Wei, L. and Dan, L.},
	title = {Effect of low-dose radiation on thyroid function and the gut microbiota},
	journal = {World Journal of Gastroenterology},
	year = {2022},
	abstract = {BACKGROUND The thyroid-gut axis has a great influence on the maintenance of human health; however, we know very little about the effects of low-dose ionizing radiation (LDR) on thyroid hormone levels and gut microbiota composition. AIM To investigate the potential effects of low-dose X-ray radiation to male C57BL/6J mice. METHODS Peripheral blood was collected for enzyme-linked immunosorbent assay (ELISA), and stool samples were taken for 16S ribosomal RNA (rRNA) gene sequencing after irradiation. RESULTS We found that LDR caused changes in thyroid stimulating hormone (TSH) levels in the irradiated mice, suggesting a dose-dependent response in thyroid function to ionizing radiation. No changes in the diversity and richness of the gut microbiota were observed in the LDR-exposed group in comparison to the controls. The abundance of Moraxellaceae and Enterobacteriaceae decreased in the LDR-exposed groups compared with the controls, and the Lachnospiraceae abundance increased in a dose-dependent manner in the radiated groups. And the abundances of uncultured_bacterium_g_Acinetobacter, uncultured_bacterium_ o_Mollicutes_RF39, uncultured_bacterium_g_Citrobacter, and uncultured_ bacterium_g_Lactococcus decreased in the radiated groups at the genus level, which showed a correlation with radiation exposure and diagnostic efficacy. Analysis of functional metabolic pathways revealed that biological metabolism was predicted to have an effect on functional activities, such as nucleotide metabolism, carbohydrate metabolism, and glycan biosynthesis and metabolism. Furthermore, Kyoto Encyclopedia of Genes and Genomes pathway annotation also suggested that changes in the gut microbiota were related to processing functions, including translation, replication and repair. CONCLUSION LDR can change thyroid function and the gut microbiota, and changes in the abundances of bacteria are correlated with the radiation dose. ©The Author(s) 2022. Published by Baishideng Publishing Group Inc. ER - ER - ER -},
	doi = {10.3748/wjg.v28.i38.5557},
	type = {JOUR}
}

@ARTICLE{10.1007/s11356-017-8392-z,
	author = {Eltahawy, N.A. and Elsonbaty, S.M. and Abunour, S. and Zahran, W.E.},
	title = {Synergistic effect of aluminum and ionizing radiation upon ultrastructure, oxidative stress and apoptotic alterations in Paneth cells of rat intestine},
	journal = {Environmental Science and Pollution Research},
	year = {2017},
	abstract = {Environmental and occupational exposure to aluminum along with ionizing radiation results in serious health problems. This study was planned to investigate the impact of oxidative stress provoked by exposure to ionizing radiation with aluminum administration upon cellular ultra structure and apoptotic changes in Paneth cells of rat small intestine. Animals received daily aluminum chloride by gastric gavage at a dose 0.5 mg/Kg BW for 4 weeks. Whole body gamma irradiation was applied at a dose 2 Gy/week up to 8 Gy. Ileum malondialdehyde, advanced oxidation protein products, and protein carbonyl were assessed as biomarkers of lipid peroxidation along with superoxide dismutase, catalase, and glutathione peroxidase activities as enzyme antioxidants. Moreover, analyses of cell cycle division and apoptotic changes were evaluated by flow cytometry. Intestinal cellular ultra structure was investigated using transmission electron microscope. Oxidative stress assessment in the ileum of rats revealed that aluminum and ionizing radiation exposure either alone or in combination exhibits a significant effect upon the increase in biomarkers of lipid peroxidation along with tumor necrosis factor-α with concomitant significant decrease of the antioxidant enzyme activities. Flow cytometric analyses showed significant alterations in the percentage of cells during cell cycle division phases along with significant increase in apoptotic cells. Ultra structurally, intestinal cellular alterations with marked injury in Paneth cells at the sites of bacterial translocation in the crypt of lumens were recorded. The results of this study have clearly suggested that aluminum exposure and ionizing either alone or in combination induced apoptosis and oxidative stress in the Paneth cells of rat intestine, which appeared to play a major role in the pathogenesis of cellular damage. Furthermore, the interaction of these two intestinal toxic routes was found to be synergistic. © 2017, Springer-Verlag Berlin Heidelberg. ER - ER - ER -},
	doi = {10.1007/s11356-017-8392-z},
	type = {JOUR}
}

@ARTICLE{10.1186/s40779-017-0116-7,
	author = {Jiang, D.-W. and Wang, Q.-R. and Shen, X.-R. and He, Y. and Qian, T.-T. and Liu, Q. and Hou, D.-Y. and Liu, Y.-M. and Chen, W. and Ren, X. and Li, K.-X.},
	title = {Radioprotective effects of cimetidine on rats irradiated by long-term, low-dose-rate neutrons and 60Co γ-rays},
	journal = {Military Medical Research},
	year = {2017},
	abstract = {Background: Cimetidine, an antagonist of histamine type II receptors, has shown protective effects against γ-rays or neutrons. However, there have been no reports on the effects of cimetidine against neutrons combined with γ-rays. This study was carried out to evaluate the protective effects of cimetidine on rats exposed to long-term, low-dose-rate neutron and γ-ray combined irradiation (n-γ LDR). Methods: Fifty male Sprague-Dawley (SD) rats were randomly divided into 5 groups: the normal control group, radiation model group, 20 mg/(kg · d) cimetidine group, 80 mg/(kg · d) cimetidine group and 160 mg/(kg · d) cimetidine group (10 rats per group). Except for the normal control group, 40 rats were simultaneously exposed to fission neutrons (252Cf, 0.085 mGy/h) for 22 h every day and γ-rays (60Co, 0.097 Gy/h) for 1.03 h once every three days, and the cimetidine groups were administered intragastrically with cimetidine at doses of 20, 80 and 160 mg/kg each day. Peripheral blood WBC of the rats was counted the day following exposure to γ-rays. The rats were anesthetized and sacrificed on the day following exposure to 252Cf for 28 days. The spleen, thymus, testicle, liver and intestinal tract indexes were evaluated. The DNA content of bone marrow cells and concanavalin A (ConA)-induced lymphocyte proliferation were measured. The frequency of micronuclei in polychromatic erythrocytes (fMNPCEs), superoxide dismutase (SOD), malondialdehyde (MDA), and glutathione peroxidase (GSH-Px) in the serum and liver tissues were detected. Results: The peripheral blood WBC in the cimetidine groups was increased significantly on the 8th day and the 26th day compared with those in the radiation model group. The spleen, thymus and testicle indexes of the cimetidine groups were higher than those of the radiation model group. The DNA content of bone marrow cells and lymphocyte proliferation in the cimetidine groups were increased significantly, and fMNPCE was reduced 1.41-1.77 fold in cimetidine treated groups. The activities of SOD and GSH-Px in the cimetidine groups were increased significantly, and the content of MDA in the cimetidine groups was decreased significantly. Conclusions: The results suggested that cimetidine alleviated damage induced by long-term, low-dose-rate neutron and γ combined irradiation via antioxidation and immunomodulation. Cimetidine might be useful as a potent radioprotector for radiotherapy patients as well as for occupational exposure workers. © 2017 The Author(s). ER - ER - ER -},
	doi = {10.1186/s40779-017-0116-7},
	type = {JOUR}
}
